import{_ as a,o as n,c as t,a4 as p}from"./chunks/framework.BDOgl-CJ.js";const k=JSON.parse('{"title":"注意力机制：Q/K/V、缩放与两种实现","description":"","frontmatter":{},"headers":[],"relativePath":"ai-learning-notes/attention-qkv-and-scaling.md","filePath":"ai-learning-notes/attention-qkv-and-scaling.md","lastUpdated":1779331987000}'),i={name:"ai-learning-notes/attention-qkv-and-scaling.md"};function e(l,s,d,o,h,r){return n(),t("div",null,[...s[0]||(s[0]=[p(`<h1 id="注意力机制-q-k-v、缩放与两种实现" tabindex="-1">注意力机制：Q/K/V、缩放与两种实现 <a class="header-anchor" href="#注意力机制-q-k-v、缩放与两种实现" aria-label="Permalink to &quot;注意力机制：Q/K/V、缩放与两种实现&quot;">​</a></h1><blockquote><p>记录于 2026-05-20，对话整理<br> 来源：李沐《Attention is All You Need》论文精读（B站）</p></blockquote><hr><h2 id="论文核心符号对照" tabindex="-1">论文核心符号对照 <a class="header-anchor" href="#论文核心符号对照" aria-label="Permalink to &quot;论文核心符号对照&quot;">​</a></h2><table tabindex="0"><thead><tr><th>符号</th><th>全称</th><th>原论文值</th><th>含义</th></tr></thead><tbody><tr><td><code>d_model</code></td><td>model dimension</td><td><strong>512</strong></td><td>每个词的向量总维度</td></tr><tr><td><code>h</code></td><td>heads</td><td><strong>8</strong></td><td>多头注意力的头数</td></tr><tr><td><code>d_k</code></td><td>key/query dimension</td><td><strong>64</strong></td><td>每个头里 Q 和 K 的维度</td></tr><tr><td><code>d_v</code></td><td>value dimension</td><td><strong>64</strong></td><td>每个头里 V 的维度</td></tr><tr><td><code>d_ff</code></td><td>feed-forward dimension</td><td><strong>2048</strong></td><td>前馈网络中间层维度</td></tr><tr><td><code>N</code></td><td>layers</td><td><strong>6</strong></td><td>Transformer 堆了几层</td></tr></tbody></table><p>核心关系：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>d_k = d_v = d_model ÷ h = 512 ÷ 8 = 64</span></span></code></pre></div><hr><h2 id="注意力机制在整体架构中的位置" tabindex="-1">注意力机制在整体架构中的位置 <a class="header-anchor" href="#注意力机制在整体架构中的位置" aria-label="Permalink to &quot;注意力机制在整体架构中的位置&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>注意力机制</span></span>
<span class="line"><span>    └── 是 Transformer 的核心组件</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Transformer</span></span>
<span class="line"><span>    └── 是现代 AI 的地基（GPT、Claude、BERT 全基于此）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>512维（d_model）</span></span>
<span class="line"><span>    └── 注意力机制运作的&quot;舞台&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Q / K / V</span></span>
<span class="line"><span>    └── 注意力机制的计算方式</span></span>
<span class="line"><span></span></span>
<span class="line"><span>64维（d_k）</span></span>
<span class="line"><span>    └── 每个头分到的维度</span></span></code></pre></div><hr><h2 id="q、k、v-是什么" tabindex="-1">Q、K、V 是什么 <a class="header-anchor" href="#q、k、v-是什么" aria-label="Permalink to &quot;Q、K、V 是什么&quot;">​</a></h2><p>每个词的 64 维向量通过三次独立的线性变换得到：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入向量（64维）</span></span>
<span class="line"><span>    ├── × W_Q  →  Q（Query，查询）  &quot;我想关注什么&quot;</span></span>
<span class="line"><span>    ├── × W_K  →  K（Key，键）      &quot;我能被谁关注&quot;</span></span>
<span class="line"><span>    └── × W_V  →  V（Value，值）    &quot;如果被关注，我传递什么内容&quot;</span></span></code></pre></div><p><strong>直觉类比：</strong></p><table tabindex="0"><thead><tr><th>角色</th><th>类比</th></tr></thead><tbody><tr><td>Q（Query）</td><td>你在图书馆的搜索关键词</td></tr><tr><td>K（Key）</td><td>每本书的书名/标签</td></tr><tr><td>V（Value）</td><td>书里真正的内容</td></tr></tbody></table><p>Q 和 K 的相似度决定&quot;要不要读这本书&quot;，V 是&quot;读到的内容&quot;。</p><hr><h2 id="完整注意力公式-逐步拆解" tabindex="-1">完整注意力公式，逐步拆解 <a class="header-anchor" href="#完整注意力公式-逐步拆解" aria-label="Permalink to &quot;完整注意力公式，逐步拆解&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Attention(Q, K, V) = softmax( Q × K^T ÷ √d_k ) × V</span></span></code></pre></div><h3 id="矩阵转置-为什么是-k-t-而不是-k" tabindex="-1">矩阵转置：为什么是 K^T 而不是 K <a class="header-anchor" href="#矩阵转置-为什么是-k-t-而不是-k" aria-label="Permalink to &quot;矩阵转置：为什么是 K^T 而不是 K&quot;">​</a></h3><p>Q 和 K 的形状都是 <code>(n × d_k)</code>，目标是算每个词对每个词的相似度（n×n 矩阵）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>不转置：Q × K = (n × d_k) × (n × d_k)  ← 维度不匹配，无效</span></span>
<span class="line"><span></span></span>
<span class="line"><span>转  置：Q × K^T = (n × d_k) × (d_k × n) = (n × n) ✓</span></span>
<span class="line"><span>                          ↑ 这里对上了</span></span></code></pre></div><p>转置就是把矩阵的行和列互换：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>K（n × d_k）：          K^T（d_k × n）：</span></span>
<span class="line"><span>┌              ┐         ┌          ┐</span></span>
<span class="line"><span>│— 词1的key — │         │ ↑  ↑  ↑ │</span></span>
<span class="line"><span>│— 词2的key — │   →     │词1 词2 词3│</span></span>
<span class="line"><span>│— 词3的key — │         │ ↓  ↓  ↓ │</span></span>
<span class="line"><span>└              ┘         └          ┘</span></span></code></pre></div><p>转置后每一<strong>列</strong>是一个词的 key 向量，Q 的每一<strong>行</strong>和它做点积，得到相似度分数。</p><p>结果矩阵里每个元素的含义：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Q × K^T 的第[i][j]个元素 = Q[i] · K[j] = 词i 和 词j 的相似度</span></span></code></pre></div><p><strong>转置的本质作用：让维度对齐，把&quot;n个向量两两点积&quot;变成一次矩阵运算，GPU 并行完成。</strong></p><h4 id="为什么维度必须-对齐" tabindex="-1">为什么维度必须&quot;对齐&quot; <a class="header-anchor" href="#为什么维度必须-对齐" aria-label="Permalink to &quot;为什么维度必须&quot;对齐&quot;&quot;">​</a></h4><p>矩阵乘法有一个硬规定：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(m × n) × (n × p) = (m × p)</span></span>
<span class="line"><span>        ↑    ↑</span></span>
<span class="line"><span>   这两个必须相等，否则无法计算</span></span></code></pre></div><p>Q 和 K 形状都是 <code>(n × d_k)</code>，比如 <code>(5 × 64)</code>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Q × K   = (5×64) × (5×64)  ❌  64 ≠ 5，不能乘</span></span>
<span class="line"><span>Q × K^T = (5×64) × (64×5)  ✓   64 = 64，结果是 (5×5)</span></span></code></pre></div><p>转置把 K 的行和列互换，让中间那个数字对上，乘法才能进行。</p><hr><h3 id="第一步-q-×-k-t-→-原始分数" tabindex="-1">第一步：Q × K^T → 原始分数 <a class="header-anchor" href="#第一步-q-×-k-t-→-原始分数" aria-label="Permalink to &quot;第一步：Q × K^T → 原始分数&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Q 矩阵形状：n × d_k   （n 个词，每词一个 query）</span></span>
<span class="line"><span>K 矩阵形状：n × d_k</span></span>
<span class="line"><span>K^T 形状：  d_k × n</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Q × K^T = n × n 矩阵</span></span>
<span class="line"><span></span></span>
<span class="line"><span>              &quot;The&quot;  &quot;cat&quot;  &quot;sat&quot;</span></span>
<span class="line"><span>&quot;The&quot; 问  →  [ 0.9,   0.1,   0.4 ]</span></span>
<span class="line"><span>&quot;cat&quot; 问  →  [ 0.2,   0.8,   0.3 ]</span></span>
<span class="line"><span>&quot;sat&quot; 问  →  [ 0.4,   0.5,   0.7 ]</span></span></code></pre></div><p>每一行是这个词对所有词的&quot;感兴趣程度&quot;原始分数。</p><h3 id="第二步-÷-√d-k-→-缩放-防止数值爆炸" tabindex="-1">第二步：÷ √d_k → 缩放，防止数值爆炸 <a class="header-anchor" href="#第二步-÷-√d-k-→-缩放-防止数值爆炸" aria-label="Permalink to &quot;第二步：÷ √d_k → 缩放，防止数值爆炸&quot;">​</a></h3><p><strong>为什么要除以 √64？</strong></p><p>Q 和 K 里每个数字均值为 0，方差为 1。做点积时 64 项相加，<strong>方差累积变成 64</strong>，标准差变成 8，数值范围从 [-1,1] 变成 [-8,8]。</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 没有缩放（数值爆炸）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">scores </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">softmax → [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.9999</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.0001</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 几乎 one-hot，梯度消失</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 除以 √64 之后（数值正常）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">scores </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">softmax → [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.67</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.25</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.08</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 分布合理，梯度健康</span></span></code></pre></div><p>除以 √d_k 把方差从 64 压回 1，让 softmax 不饱和。</p><h3 id="第三步-softmax-→-变成概率分布" tabindex="-1">第三步：softmax → 变成概率分布 <a class="header-anchor" href="#第三步-softmax-→-变成概率分布" aria-label="Permalink to &quot;第三步：softmax → 变成概率分布&quot;">​</a></h3><p>每行所有分数加起来 = 1，代表&quot;这个词的注意力分配方案&quot;。</p><h3 id="第四步-×-v-→-加权求和-得到新表示" tabindex="-1">第四步：× V → 加权求和，得到新表示 <a class="header-anchor" href="#第四步-×-v-→-加权求和-得到新表示" aria-label="Permalink to &quot;第四步：× V → 加权求和，得到新表示&quot;">​</a></h3><p>用注意力权重把 Value 加权求和，输出每个词更新后的向量。</p><hr><h2 id="加型注意力-vs-点积注意力" tabindex="-1">加型注意力 vs 点积注意力 <a class="header-anchor" href="#加型注意力-vs-点积注意力" aria-label="Permalink to &quot;加型注意力 vs 点积注意力&quot;">​</a></h2><p>两种计算注意力分数的方法：</p><table tabindex="0"><thead><tr><th></th><th>点积注意力</th><th>加型注意力（Bahdanau）</th></tr></thead><tbody><tr><td>公式</td><td><code>Q·K^T ÷ √d_k</code></td><td><code>W_v · tanh(W_q·Q + W_k·K)</code></td></tr><tr><td>额外参数</td><td>无</td><td>有（W_q、W_k、W_v）</td></tr><tr><td>速度</td><td>快（矩阵乘法，GPU 极度优化）</td><td>慢</td></tr><tr><td>提出时间</td><td>2017（Transformer）</td><td>2015（Bahdanau）</td></tr><tr><td>现状</td><td>主流，GPT/Claude 都用</td><td>少数场景</td></tr></tbody></table><p><strong>为什么点积赢了？</strong></p><ul><li>d_k 较小时两者效果差不多</li><li>d_k 较大时，点积不缩放会崩，但除以 √d_k 修正后效果相当</li><li>点积的矩阵乘法在 GPU 上有极度优化的实现，速度远快于加型</li></ul><p>加型注意力需要额外的神经网络层，无法充分利用 GPU 并行能力。<strong>工程效率决定了胜负。</strong></p><hr><h2 id="自回归-llm-生成文字的方式" tabindex="-1">自回归：LLM 生成文字的方式 <a class="header-anchor" href="#自回归-llm-生成文字的方式" aria-label="Permalink to &quot;自回归：LLM 生成文字的方式&quot;">​</a></h2><p>GPT、Claude 这类模型生成文字不是一口气蹦出来的，而是<strong>每次只生成一个 token，把它拼到上下文里，再预测下一个</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入：「今天天气」</span></span>
<span class="line"><span>→ 生成「很」</span></span>
<span class="line"><span>→ 输入变成「今天天气很」→ 生成「好」</span></span>
<span class="line"><span>→ 输入变成「今天天气很好」→ 生成「。」</span></span></code></pre></div><p>每一步都在&quot;回归&quot;自己已经生成的内容，所以叫<strong>自回归生成（Autoregressive Generation）</strong>。</p><p>这就是为什么 LLM 的输出是逐字出来的——它本质上是在循环做预测。</p><hr><h2 id="完整流程总结" tabindex="-1">完整流程总结 <a class="header-anchor" href="#完整流程总结" aria-label="Permalink to &quot;完整流程总结&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入词</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>d_model = 512 维 Embedding（词的&quot;身份证&quot;）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>多头注意力（h=8 个头，每头 d_k=64 维）</span></span>
<span class="line"><span>  ├─ 每头得到 Q、K、V（各 64 维）</span></span>
<span class="line"><span>  ├─ score = softmax( Q·K^T ÷ √64 ) × V</span></span>
<span class="line"><span>  └─ 8 个头拼回 512 维</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>前馈网络（512 → d_ff=2048 → 512）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>重复 N=6 层</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>输出</span></span></code></pre></div>`,64)])])}const g=a(i,[["render",e]]);export{k as __pageData,g as default};
